1	import { describe, it, expect } from "vitest";
2	import request from "supertest";
3	import { app } from "../src/app.js";
4	
5	describe("GET /orders", () => {
6	  it("should return all orders with summary", async () => {
7	    const res = await request(app).get("/orders");
8	    expect(res.status).toBe(200);
9	    expect(res.body.orders.length).toBeGreaterThanOrEqual(2);
10	    expect(res.body.summary).toHaveProperty("count");
11	    expect(res.body.summary).toHaveProperty("totalRevenue");
12	  });
13	
14	  it("should filter by status", async () => {
15	    const res = await request(app).get("/orders?status=confirmed");
16	    expect(res.status).toBe(200);
17	    for (const o of res.body.orders) {
18	      expect(o.status).toBe("confirmed");
19	    }
20	  });
21	});
22	
23	describe("GET /orders/:id", () => {
24	  it("should return an order with enriched items", async () => {
25	    const res = await request(app).get("/orders/1");
26	    expect(res.status).toBe(200);
27	    expect(res.body.items[0]).toHaveProperty("productName");
28	    expect(res.body.items[0].productName).toBe("Laptop");
29	  });
30	
31	  it("should return 404 for non-existent order", async () => {
32	    const res = await request(app).get("/orders/999");
33	    expect(res.status).toBe(404);
34	  });
35	});
36	
37	describe("POST /orders", () => {
38	  it("should create a new order", async () => {
39	    const res = await request(app)
40	      .post("/orders")
41	      .send({
42	        userId: 1,
43	        items: [{ productId: 2, quantity: 1 }],
44	      });
45	    expect(res.status).toBe(201);
46	    expect(res.body.status).toBe("pending");
47	    expect(res.body.total).toBe(29.99);
48	  });
49	
50	  it("should reject order with invalid items", async () => {
51	    const res = await request(app)
52	      .post("/orders")
53	      .send({ userId: 1, items: [] });
54	    expect(res.status).toBe(400);
55	  });
56	
57	  it("should reject order for non-existent product", async () => {
58	    const res = await request(app)
59	      .post("/orders")
60	      .send({
61	        userId: 1,
62	        items: [{ productId: 999, quantity: 1 }],
63	      });
64	    expect(res.status).toBe(400);
65	  });
66	});
67	
68	describe("PATCH /orders/:id/status", () => {
69	  it("should update order status", async () => {
70	    const res = await request(app)
71	      .patch("/orders/2/status")
72	      .send({ status: "confirmed" });
73	    expect(res.status).toBe(200);
74	    expect(res.body.status).toBe("confirmed");
75	  });
