      expect(p.price).toBeGreaterThanOrEqual(100);
      expect(p.price).toBeLessThanOrEqual(500);
    }
  });
});

describe("GET /products/:id", () => {
  it("should return a product with extra fields", async () => {
    const res = await request(app).get("/products/1");
